const expectedToken = 'REPLACE_WITH_RABBIT_TOKEN';

function parsePayload(input) {
  const direct = input.payload ?? input.body?.payload ?? input.body ?? input;

  if (typeof direct === 'string') {
    try {
      return JSON.parse(direct);
    } catch (error) {
      return { message: direct };
    }
  }

  return direct || {};
}

const payload = parsePayload($json);
const token = String(payload.token || payload.apiKey || payload.key || '');
const tokenConfigured = expectedToken && !expectedToken.startsWith('REPLACE_WITH_');
const valid = Boolean(tokenConfigured && token === expectedToken);
const message = String(payload.message || payload.text || payload.transcript || '').trim();
const now = new Date().toISOString();

return [{
  json: {
    valid,
    revoked: !valid,
    status: valid ? 'ok' : 'revoked',
    reply: valid ? 'Procesando Mind Drop.' : 'Token revocado o invalido.',
    message,
    inputMode: String(payload.inputMode || 'text'),
    sessionId: String(payload.sessionId || ''),
    source: String(payload.source || 'rabbit-r1-creation'),
    sentAt: payload.sentAt || now,
    receivedAt: now
  }
}];

const openAiApiKey = 'REPLACE_WITH_OPENAI_API_KEY';
const allowedAreas = ['Salud', 'Trabajo', 'Finanzas', 'Relaciones', 'Casa', 'Aprendizaje', 'Ideas', 'Personal'];
const message = String($json.message || '').trim();

function cleanArea(value) {
  const normalized = String(value || '').trim();
  return allowedAreas.includes(normalized) ? normalized : 'Personal';
}

function fallback(reason = '') {
  const title = message ? message.slice(0, 80) : 'Mind Drop';
  return [{
    json: {
      ...$json,
      titulo: title,
      area: 'Personal',
      observaciones: message || 'Sin mensaje recibido.',
      aiModel: 'fallback',
      aiFallbackReason: reason
    }
  }];
}

if (!message) return fallback('empty_message');
if (!openAiApiKey || openAiApiKey.startsWith('REPLACE_WITH_')) return fallback('missing_openai_key');

const system = [
  'Eres un clasificador de capturas personales llamado Mind Drop.',
  'Recibes una nota breve en espanol y devuelves solo JSON valido.',
  'Campos obligatorios: titulo, area, observaciones.',
  `area debe ser exactamente una de: ${allowedAreas.join(', ')}.`,
  'titulo: maximo 80 caracteres, claro y util como titulo de pagina.',
  'observaciones: reescribe el mensaje de forma clara y accionable en 1-3 frases.',
  'Si hay duda entre areas, usa Personal. Si es una idea suelta, usa Ideas.'
].join(' ');

try {
  const response = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${openAiApiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'gpt-4.1-nano',
      temperature: 0.1,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: message }
      ]
    })
  });

  const data = await response.json();
  if (!response.ok) return fallback(`openai_http_${response.status}`);

  const content = data.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  const titulo = String(parsed.titulo || parsed.title || message).trim().slice(0, 80) || 'Mind Drop';
  const area = cleanArea(parsed.area);
  const observaciones = String(parsed.observaciones || parsed.notes || parsed.observation || message).trim();

  return [{
    json: {
      ...$json,
      titulo,
      area,
      observaciones,
      aiModel: 'gpt-4.1-nano'
    }
  }];
} catch (error) {
  return fallback(error.message || 'openai_error');
}

return [{
  json: {
    ok: true,
    status: 'ok',
    reply: `Guardado en Mind Drop: ${$json.Titulo || $json.titulo || 'nuevo drop'}.`,
    notionPageId: $json.id || '',
    area: $json.Area || $json.area || ''
  }
}];

return [{
  json: {
    ok: false,
    revoked: true,
    status: 'revoked',
    reply: 'Token revocado o invalido.'
  }
}];
